body.script:
//
(function() {
  var tabs = [],
    tabCounter = 1,
    activeTabId = 0,
    tabHistory = {};

  function createTab(b) {
    var a = tabCounter++,
      c = document.createElement("div");
    c.className = "tab";
    c.dataset.tab = a;
    c.innerHTML = '<span>Loading...</span><button class="tab-close" onclick="event.stopPropagation();closeTab(' + a + ')">&#10005;</button>';
    c.onclick = function() {
      switchTab(a)
    };
    var d = document.querySelector(".new-tab-btn");
    d.parentNode.insertBefore(c, d);
    var e = document.createElement("div");
    e.className = "tab-content";
    e.dataset.tab = a;
    if (b) {
      var f = document.createElement("iframe");
      f.id = "sj-frame-" + a;
      f.style.width = "100%";
      f.style.height = "100%";
      f.style.border = "none";
      f.style.background = "#202124";
      e.appendChild(f)
    } else e.innerHTML = '<div class="new-tab-page"><div class="logo">zaka13</div><div class="shortcuts-grid"><div class="shortcut-btn" data-url="https://discord.com"><div style="width:48px;height:48px;border-radius:12px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:bold;color:#5865F2;font-family:Arial">D</div><span class="shortcut-label">Discord</span></div><div class="shortcut-btn" data-url="https://www.google.com"><div style="width:48px;height:48px;border-radius:12px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:bold;color:#4285F4;font-family:Arial">G</div><span class="shortcut-label">Google</span></div><div class="shortcut-btn" data-url="https://www.youtube.com"><div style="width:48px;height:48px;border-radius:12px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:bold;color:#FF0000;font-family:Arial">Y</div><span class="shortcut-label">YouTube</span></div><div class="shortcut-btn" data-url="https://zaka13alt.github.io/Extra-assets-/games.html"><div style="width:48px;height:48px;border-radius:12px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:bold;color:#66CC66;font-family:Arial">G</div><span class="shortcut-label">Games</span></div></div></div>';
    document.getElementById("content-area").appendChild(e);
    tabs.push({
      id: a,
      element: c,
      content: e,
      url: b || null,
      iframe: b ? e.querySelector("iframe") : null,
      history: [],
      historyIndex: -1
    });
    tabHistory[a] = {
      stack: [],
      index: -1
    };
    switchTab(a);
    updateTabCounts();
    b && navigateTab(a, b);
    return a
  }

  function switchTab(a) {
    activeTabId = a;
    document.querySelectorAll(".tab").forEach(function(b) {
      b.classList.remove("active")
    });
    document.querySelectorAll(".tab-content").forEach(function(b) {
      b.classList.remove("active")
    });
    var b = tabs.find(function(c) {
      return c.id === a
    });
    if (b) {
      b.element.classList.add("active");
      b.content.classList.add("active");
      var c = b.url || "";
      document.getElementById("sj-address").value = c;
      updateNavButtons(a)
    }
  }

  function closeTab(a) {
    if (tabs.length <= 1) {
      var b = tabs.find(function(c) {
        return c.id === a
      });
      if (b) {
        b.url = null;
        b.iframe = null;
        b.content.innerHTML = '<div class="new-tab-page"><div class="logo">&#10022; zaka13</div><div class="shortcuts-grid"><div class="shortcut-btn" data-url="https://discord.com"><div style="width:48px;height:48px;border-radius:12px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:bold;color:#5865F2;font-family:Arial">D</div><span class="shortcut-label">Discord</span></div><div class="shortcut-btn" data-url="https://www.google.com"><div style="width:48px;height:48px;border-radius:12px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:bold;color:#4285F4;font-family:Arial">G</div><span class="shortcut-label">Google</span></div><div class="shortcut-btn" data-url="https://www.youtube.com"><div style="width:48px;height:48px;border-radius:12px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:bold;color:#FF0000;font-family:Arial">Y</div><span class="shortcut-label">YouTube</span></div><div class="shortcut-btn" data-url="https://example.com"><div style="width:48px;height:48px;border-radius:12px;background:#1a1a2e;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:bold;color:#66CC66;font-family:Arial">G</div><span class="shortcut-label">Games</span></div></div></div>';
        b.element.querySelector("span").textContent = "New Tab";
        document.getElementById("sj-address").value = "";
        switchTab(a);
        updateTabCounts()
      }
      return
    }
    var c = tabs.findIndex(function(d) {
      return d.id === a
    });
    if (c === -1) return;
    tabs[c].element.remove();
    tabs[c].content.remove();
    tabs.splice(c, 1);
    if (activeTabId === a) {
      var d = tabs[Math.min(c, tabs.length - 1)];
      d && switchTab(d.id)
    }
    updateTabCounts()
  }

  function updateTabCounts() {
    tabs.forEach(function(a) {
      var b = a.element.querySelector("span");
      if (a.url) try {
        var c = new URL(a.url);
        b.textContent = c.hostname.replace("www.", "")
      } catch (d) {
        b.textContent = a.url.substring(0, 20)
      } else b.textContent = "New Tab"
    })
  }

  function updateNavButtons(a) {
    var b = tabHistory[a] || {
      stack: [],
      index: -1
    };
    document.getElementById("back-btn").disabled = b.index <= 0;
    document.getElementById("forward-btn").disabled = b.index >= b.stack.length - 1
  }
  var BASE_PATH = location.pathname.replace(/\/[^\/]*$/, "/"),
    swAllowedHostnames = ["localhost", "127.0.0.1"],
    controllers = {},
    frames = {};

  function search(a, b) {
    try {
      return new URL(a).toString()
    } catch (c) {}
    try {
      var d = new URL("http://" + a);
      if (d.hostname.includes(".")) return d.toString()
    } catch (c) {}
    if (a.includes("zaka") || a.includes("zaka13")) alert("Why you searching my name up?\nlmfao");
    return b.replace("%s", encodeURIComponent(a))
  }
  async function registerSW() {
    if (!navigator.serviceWorker) {
      if (location.protocol !== "https:" && !swAllowedHostnames.includes(location.hostname)) throw new Error(
        "Service workers cannot be registered without https.");
      throw new Error("Your browser doesn't support service workers.");
    }
    await navigator.serviceWorker.register(BASE_PATH + "sw.js", {
      scope: BASE_PATH,
      updateViaCache: "none"
    })
  }
  var wispInput = document.getElementById("wisp-server"),
    currentWisp = wispInput.value.trim() || "wss://wisp.zaka.qzz.io/wisp/";
  wispInput.addEventListener("change", function() {
    var a = this.value.trim();
    if (a) {
      currentWisp = a;
      controllers = {};
      frames = {}
    }
  });
  async function initController(a) {
    if (controllers[a]) return controllers[a];
    var b = window.$scramjetController.Controller,
      c = window.$scramjetController.config;
    c.scramjetPath = location.origin + BASE_PATH + "scj/scj.js";
    c.wasmPath = location.origin + BASE_PATH + "scj/scj.wasm";
    c.injectPath = location.origin + BASE_PATH + "controller/controller.inject.js";
    c.prefix = BASE_PATH + "~sj/";
    var d = new window.LibcurlTransport.LibcurlClient({
        wisp: currentWisp
      }),
      e = new b({
        serviceworker: navigator.serviceWorker.controller,
        transport: d
      });
    await e.wait();
    controllers[a] = e;
    return e
  }
  async function navigateTab(a, b) {
    if (!b.startsWith("http") && !b.startsWith("https://")) b = search(b, document.getElementById("sj-search-engine")
      .value);
    if (!b.startsWith("http")) b = "https://" + b;
    var c = tabs.find(function(d) {
      return d.id === a
    });
    if (!c) return;
    c.url = b;
    document.getElementById("sj-address").value = b;
    try {
      var e = new URL(b);
      c.element.querySelector("span").textContent = e.hostname.replace("www.", "")
    } catch (f) {
      c.element.querySelector("span").textContent = b.substring(0, 20)
    }
    if (!c.iframe) {
      c.content.innerHTML = "";
      var g = document.createElement("iframe");
      g.id = "sj-frame-" + a;
      g.style.width = "100%";
      g.style.height = "100%";
      g.style.border = "none";
      g.style.background = "#202124";
      c.content.appendChild(g);
      c.iframe = g;
      if (!tabHistory[a]) tabHistory[a] = {
        stack: [],
        index: -1
      };
      tabHistory[a].stack.push(b);
      tabHistory[a].index = tabHistory[a].stack.length - 1
    }
    try {
      await registerSW()
    } catch (f) {
      alert("Failed to register service worker: " + f.toString());
      return
    }
    if (!navigator.serviceWorker.controller) await new Promise(function(f) {
      navigator.serviceWorker.addEventListener("controllerchange", f, {
        once: true
      })
    });
    try {
      var h = await initController(a),
        i = h.createFrame(c.iframe);
      if (!i) throw new Error("createFrame returned null");
      frames[a] = i;
      await i.go(b);
      if (!tabHistory[a]) tabHistory[a] = {
        stack: [],
        index: -1
      };
      tabHistory[a].stack.push(b);
      tabHistory[a].index = tabHistory[a].stack.length - 1;
      updateNavButtons(a)
    } catch (f) {
      alert("Navigation error: " + f.message)
    }
  }
  document.getElementById("sj-address").addEventListener("keydown", function(a) {
    if (a.key === "Enter") {
      a.preventDefault();
      var b = this.value.trim();
      b && navigateTab(activeTabId, b)
    }
  });
  document.getElementById("back-btn").addEventListener("click", function() {
    var a = tabHistory[activeTabId];
    if (a && a.index > 0) {
      a.index--;
      var b = a.stack[a.index];
      if (b) {
        var c = tabs.find(function(d) {
          return d.id === activeTabId
        });
        if (c) {
          c.url = b;
          document.getElementById("sj-address").value = b;
          frames[activeTabId] && frames[activeTabId].go(b);
          updateNavButtons(activeTabId)
        }
      }
    }
  });
  document.getElementById("forward-btn").addEventListener("click", function() {
    var a = tabHistory[activeTabId];
    if (a && a.index < a.stack.length - 1) {
      a.index++;
      var b = a.stack[a.index];
      if (b) {
        var c = tabs.find(function(d) {
          return d.id === activeTabId
        });
        if (c) {
          c.url = b;
          document.getElementById("sj-address").value = b;
          frames[activeTabId] && frames[activeTabId].go(b);
          updateNavButtons(activeTabId)
        }
      }
    }
  });
  document.addEventListener("click", function(a) {
    var b = a.target.closest(".shortcut-btn");
    if (b) {
      var c = b.dataset.url;
      c && navigateTab(activeTabId, c)
    }
  });
  window.createTab = createTab;
  window.closeTab = closeTab;
  window.switchTab = switchTab;
  window.navigateTab = navigateTab;
  var goto = new URL(location.href).searchParams.get("goto");
  if (goto) {
    history.replaceState(null, "", location.pathname);
    setTimeout(function() {
      navigateTab(0, goto)
    }, 500)
  }
})();
//

svg.script:
var fo = document.getElementById("fo");

function r() {
  fo.setAttribute("width", window.innerWidth);
  fo.setAttribute("height", window.innerHeight);
}
r();
window.addEventListener("resize", r);
